import{_ as e,c as s,o as r,R as n}from"./chunks/framework.CIzs38F0.js";const u=JSON.parse('{"title":"1. Ingress Controller控制器的工作原理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/container/k8s/Ingress/ingress_nginx/index.md","filePath":"guide/container/k8s/Ingress/ingress_nginx/index.md","lastUpdated":1716287268000}'),o={name:"guide/container/k8s/Ingress/ingress_nginx/index.md"},l=n('<h1 id="_1-ingress-controller控制器的工作原理" tabindex="-1">1. Ingress Controller控制器的工作原理 <a class="header-anchor" href="#_1-ingress-controller控制器的工作原理" aria-label="Permalink to &quot;1. Ingress Controller控制器的工作原理&quot;">​</a></h1><p>Ingress Controller用于解析lngress的转发规则。Ingress Controller收到请求，匹配Ingress转发规则转发到后端Service所对应的Pod，由Pod处理请求。Kubernetes中Service、Ingress与lngress Controller有着以下关系：</p><ul><li>service是后端真实服务的抽象，一个Service可以代表多个相同的后端服务。</li><li>Ingress是反向代理规则，用来规定HTTP、HTTPS请求应该被转发到哪个Service所对应的Pod上。</li><li>IngressController是一个反向代理程序，负责解析lngress的反向代理规则。如果Ingress有增删改的变动，Ingress Controller会及时更新自己相应的转发规则，当IngressController收到请求后就会根据这些规则将请求转发到对应Service的Pod上。</li></ul><p>IngressController通过API Server获取lngress资源的变化，并动态地更新Nginx配置文件，实现HTTP(S)的负载均衡及路由转发。</p><blockquote><p>白话，Ingress Controller控制器的工作原理，简单来说，将控制器理解为一个监听器，通过不断地监听 kube-apiserver，实时的感知后端 Service和Pod的变化，当得到这些信息变化后，Ingress Controller再结合Ingress的配置，更新反向代理负载均衡器，从而达到服务发现的作用。Ingress-nginx的最终目标是构造nginx.conf这样的配置文件，主要用途是在配置文件有任何变更后都需要重新加载 nginx</p></blockquote><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202405221747632.png" alt="image-20240522174729110"></p><div class="danger custom-block"><p class="custom-block-title">❌ 注意</p><p>Kubernetes的Ingress资源对象需要配合IngressController才能实现外部流量的转发和路由。IngressController是Ingress资源的实际执行者，负责根据定义的路由规则配置网络代理。（Ingress/Ingress Controller干万不要搞混)</p></div>',7),t=[l];function i(g,a,c,d,_,I){return r(),s("div",null,t)}const C=e(o,[["render",i]]);export{u as __pageData,C as default};
